import{_ as t,o as l,c as r,ak as n}from"./chunks/framework.D3PFo-vo.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"chinese/文言翻译.md","filePath":"chinese/文言翻译.md"}'),e={name:"chinese/文言翻译.md"};function s(i,o,a,g,c,u){return l(),r("div",null,[...o[0]||(o[0]=[n('<h2 style="text-align:center;font-size:30px;">文言翻译</h2><h4 id="一、考点解读" tabindex="-1">一、考点解读 <a class="header-anchor" href="#一、考点解读" aria-label="Permalink to &quot;一、考点解读&quot;">​</a></h4><p>文言文翻译，是对文言文阅读能力的综合考查，是文言文阅读考查的重点和难点。 近年来新高考、全国卷翻译题的<strong>分值均为8分</strong>，题号为第13小题，题干一般表述为：“<strong>把文中画横线的句子翻译成现代汉语</strong>。”共两个小题，每个小题有3-4个小句子。翻译考查一般采取<strong>按点赋分</strong>的方法，一般每个小句子中均有赋分点。 根据近年文言文翻译的命题选材和评分细则，翻译题所选句子主要有以下特点：</p><ul><li>（1）句子中含有特别<strong>重要的文言实、虚词</strong>，且注重与教材的勾连，<strong>教考衔接</strong>；</li><li>（2)句子中有<strong>通假、古今异义、一词多义、词类活用、特殊句式</strong>等文言现象；</li><li>（3)句意推断往往需结<strong>合上下文语境</strong>才能准确理解。</li></ul><h4 id="二、基本方法" tabindex="-1">二、基本方法 <a class="header-anchor" href="#二、基本方法" aria-label="Permalink to &quot;二、基本方法&quot;">​</a></h4><ul><li><h4 id="文言翻译的基本方法需掌握六个字-留、删、换、调、补、变" tabindex="-1">文言翻译的基本方法需掌握六个字：<strong>留、删、换、调、补、变</strong> <a class="header-anchor" href="#文言翻译的基本方法需掌握六个字-留、删、换、调、补、变" aria-label="Permalink to &quot;文言翻译的基本方法需掌握六个字：**留、删、换、调、补、变**&quot;">​</a></h4></li><li><h5 id="_1、留" tabindex="-1">1、留 <a class="header-anchor" href="#_1、留" aria-label="Permalink to &quot;1、留&quot;">​</a></h5><blockquote><p><strong>凡朝代、年号、人名、地名、书名、器物名、官职等专有名词或现代汉语也通用的词，皆保留不动。成语要简单翻译。</strong></p></blockquote><ul><li>（1）赵惠文王十六年，廉颇为赵将伐齐，大破之，取阳晋，拜为上卿，以勇气闻于诸侯。（《廉颇蔺相如列传》）</li></ul><blockquote><p>译文：<strong>赵惠文王十六年</strong>，<strong>廉颇</strong>作为赵国大将攻打齐国，大败齐国，攻取<strong>阳晋</strong>，被任命为<strong>上卿</strong>，凭借<strong>勇气</strong>在<strong>诸侯</strong>中闻名。</p></blockquote><ul><li>（2）后悼公十四年，知氏乃亡。此先后甚远，而韩非公称之，曾无怍意。（2023年新课标全国Ⅰ卷）</li></ul><blockquote><p>译文：后来在<strong>悼公十四年</strong>，<strong>知氏</strong>才灭亡。这两个事件之间相隔很久，<strong>韩非子</strong>提到了它们，竟然没有一点惭愧之意。（知识迁移：《愚公移山》曾不若孀妻弱子。）</p></blockquote></li><li><h5 id="_2-删" tabindex="-1">2.删 <a class="header-anchor" href="#_2-删" aria-label="Permalink to &quot;2.删&quot;">​</a></h5><blockquote><p>把<strong>无实义</strong>或<strong>没必要译出</strong>的虚词（如<strong>句首发语词、句末语气词、句中停顿的词、凑音节的助词、结构倒装的标志等</strong>）、<strong>偏义复词中无实义的一方</strong>等删去。</p></blockquote><ul><li>【练习2】圈出下列句中翻译时需删去的词： <ul><li>（1）<strong>夫</strong>晋，<strong>何</strong>厌之有？（《烛之武退秦师》） （<code>夫，句首发语词</code>；<code>之，助词，宾前标志</code>）</li><li>（2）师道<strong>之</strong>不传<strong>也</strong>久<strong>矣</strong>。（《师说》） （<code>之，结构助词</code>；<code>也/矣，语气助词</code>）</li><li>（3）备他盗<strong>之出</strong>入与非常<strong>也</strong>。（《鸿门宴》） （<code>之，结构助词</code>；<code>出，偏义复词无实义一方</code>；<code>也，语气助词</code>）</li></ul></li></ul></li><li><h5 id="_3-换" tabindex="-1">3.换 <a class="header-anchor" href="#_3-换" aria-label="Permalink to &quot;3.换&quot;">​</a></h5><blockquote><p>翻译时把古代词汇换成现代汉语。基本模式是<strong>把单音节词换成双音节词（组词法）</strong>，<strong>通假字换成本字</strong>，<strong>古今异义</strong>、<strong>词类活用</strong>词换成现代汉语。</p></blockquote><ul><li>（1）<strong>疏</strong>屈平而<strong>信</strong>上官大夫。    《屈原列传》 <code>疏远</code>   <code>信任</code>   <strong>（单换双）</strong></li><li>（2）天下<strong>云</strong>集<strong>响</strong>应，赢粮而<strong>景</strong>从。《过秦论》 <code>像云、回声、影子一样。</code>（词类活用，名作状，景通“影”）</li></ul></li><li><h5 id="_4-调" tabindex="-1">4.调 <a class="header-anchor" href="#_4-调" aria-label="Permalink to &quot;4.调&quot;">​</a></h5><blockquote><p>文言文中<strong>一些特殊句式要按照现代汉语的语法调整语序</strong>。</p></blockquote><ul><li>【练习4】请判断下面句子的特殊类型，并写出句子的正确语序。 <ul><li>（1）句读之不知，惑之不解。（《师说》） <blockquote><p>特殊句式： 宾语前置          正确语序为：不知句读，不解惑</p></blockquote></li><li>（2）“宜乎百姓之谓我爱也！”（《齐桓晋文之事》） <blockquote><p>特殊句式：  主谓倒装         正确语序为：百姓之谓我爱也宜乎 ！</p></blockquote></li><li>（3）蚓无爪牙之利，筋骨之强， 上食埃土，下饮黄泉。用心一也。（《劝学》） <blockquote><p>特殊句式： 定语后置         正确语序为：蚓无利爪牙，强筋骨。</p></blockquote></li><li>（4）莫之能御也。（《齐桓晋文之事》） <blockquote><p>特殊句式： 宾语前置         正确语序为：莫能御之也。</p></blockquote></li><li>（5）具告以事。 （《鸿门宴》） <blockquote><p>特殊句式： 状语后置         正确语序为：以事具告之。</p></blockquote></li></ul></li></ul></li><li><h5 id="_5-补" tabindex="-1">5.补 <a class="header-anchor" href="#_5-补" aria-label="Permalink to &quot;5.补&quot;">​</a></h5><blockquote><p>补出文句中省略了的内容（如主语、谓语、宾语、介词等）。</p></blockquote><ul><li>【练习5】仿照示例补出文句中省略的内容 <ul><li>（1）拜臣（为）郎中。     （《陈情表》）（省略谓语）</li><li>（2）（臣）今老矣，无能为也已     （《烛之武退秦师》）（省略主语）</li><li>（3）孺卿从（帝）祠（于）河东后土。（《苏武传》）（省略宾语和介词）</li></ul></li></ul></li><li><h5 id="_6-变" tabindex="-1">6.变 <a class="header-anchor" href="#_6-变" aria-label="Permalink to &quot;6.变&quot;">​</a></h5><blockquote><p>指根据语境，灵活变通地翻译。这往往是上述五种方法都用上了，还难以准确翻译时的一种方法。尤其是碰到文言文中<strong>运用修辞或典故</strong>的地方时，应学会变通地翻译，进行<strong>意译</strong>。</p></blockquote><ul><li>【练习6】翻译下面的句子，特别注意加点字词的翻译。 <ul><li>（1）吾入关，秋毫不敢有所近。（《鸿门宴》）【比喻】 <blockquote><p>【译文】我进入关中，<strong>一丝一毫的财物</strong>不敢据为己有。 （“秋毫”的意思是秋天鸟兽身上新长出的细毛，用来比喻极其细微的事物。）</p></blockquote></li><li>（2）臣生当殒首，死当结草。（《陈情表》） 【典故】 <blockquote><p>【译文】 臣活着应当不惜牺牲性命为国出力，死后也要<strong>像结草老人那样</strong>报答陛下的大恩。 （“陨首”意译，“结草”用典，应译出典故的内涵。）</p></blockquote></li><li>（3）燕赵之收藏，韩魏之经营，齐楚之精英。（杜牧《阿房宫赋》）【互文】 <blockquote><p>【译文】<strong>燕、赵、韩、魏、齐、楚</strong>六国收藏的<strong>金玉珍宝</strong>。 （“收藏”“经营”“精英”使用互文手法，可以合译。）</p></blockquote></li></ul></li></ul></li><li><h4 id="四、文言翻译的基本原则" tabindex="-1">四、文言翻译的基本原则 <a class="header-anchor" href="#四、文言翻译的基本原则" aria-label="Permalink to &quot;四、文言翻译的基本原则&quot;">​</a></h4><ul><li><h5 id="文言翻译遵循-字字落实-直译为主-意译为辅-的翻译原则。" tabindex="-1">文言翻译遵循“<strong>字字落实，直译为主，意译为辅</strong>”的翻译原则。 <a class="header-anchor" href="#文言翻译遵循-字字落实-直译为主-意译为辅-的翻译原则。" aria-label="Permalink to &quot;文言翻译遵循“**字字落实，直译为主，意译为辅**”的翻译原则。&quot;">​</a></h5></li><li>直译：译文与原文有准确的对应关系，<strong>单音节变双音节</strong>。</li><li>意译：在保持原意不变的前提下，灵活处理句式与修辞。需要意译的多是一些<strong>典故、习惯用法、修辞手法</strong>（如互文）等。</li><li>这就要求我们，在具体翻译时，对句子中的每个字词，只要它有一定的实在意义，都必须字字落实，对号入座。翻译时，要<strong>按照原文的词义和词序</strong>（有语序倒装的要按调整后的语序），把文言文对换成相应的现代汉语。如果<strong>直译后语意不畅，还应用意译作为辅助手段</strong>，使句意更加通顺流畅。</li></ul></li><li><h4 id="五、文言翻译的三大意识" tabindex="-1">五、文言翻译的三大意识 <a class="header-anchor" href="#五、文言翻译的三大意识" aria-label="Permalink to &quot;五、文言翻译的三大意识&quot;">​</a></h4><ul><li>1.原则意识<strong>字字落实，直译为主，意译为辅</strong></li><li>2.语境意识   句意推断需结合上下文语境来理解是近年来高考中文言翻译的常设考查点。正如实词推断方法中讲到的“语境推断法”，语境对于翻译同样非常重要，要把句子代入原文中去读、去思考，结合语境推断重点实虚词，结合语境推断被省略的成分等，真正做到<strong>字回词中，词回句中，句回段中，段回篇中</strong>。</li><li>3.得分点意识 在翻译句子的时候树立得分点意识，<strong>有意识地找到每个句子中的得分点</strong>，如重点实词、重点虚词、特殊句式，将其通过直译、意译或推断一一<strong>落实到位</strong>。</li></ul></li><li><h4 id="六、文言翻译的基本步骤" tabindex="-1">六、文言翻译的基本步骤 <a class="header-anchor" href="#六、文言翻译的基本步骤" aria-label="Permalink to &quot;六、文言翻译的基本步骤&quot;">​</a></h4><ul><li>第一步：结合<strong>上下文语境</strong>，通读句子，整体理解。</li><li>第二步：根据<strong>得分点</strong>，<strong>圈定</strong>实词、虚词、特殊句式等。</li><li>第三步：<strong>逐字翻译</strong>，连词成句。</li><li>第四步：检查润色，查漏补缺，保证<strong>通顺流畅</strong>。</li></ul></li></ul>',6)])])}const b=t(e,[["render",s]]);export{d as __pageData,b as default};
